#include <bits/stdc++.h>using namespace std;int t;int n, k, d;int a[2010], v[100010];int cnt[4010];int main() {	cin>>t;	while (t--) 	{		cin>>n>>k>>d;		cnt[0]=0;		for (int i=1;i<=n;++i) 		{			cin>>a[i];			cnt[0]+=a[i]==i;		}		for(int i=1;i<=k;++i) 		{			cin>>v[i];		}		for (int i = 1; i <= 2 * n && i < d; ++i) 		{			cnt[i] = 0;			for (int j = 1; j <= v[(i - 1) % k + 1]; ++j) 			{				a[j]++;			}			for (int j = 1; j <= n; ++j) 			{				cnt[i] += (a[j]==j);			}		}		int ans = 0;		for (int i = 0; i <= 2 * n && i < d; ++i) 		{			ans=max(ans, cnt[i] + (d - i - 1) / 2);		}		cout<<ans<<endl; 	}	return 0;}